import { contextBridge, ipcRenderer } from 'electron';
import { Channels } from '../shared/channels';
import type {
  ActivationResult,
  ActivationState,
  DependencyStatus,
  InstallProgress,
  PermissionStatus,
} from '../shared/activation-types';

const onboardingAPI = {
  activate: (email: string): Promise<ActivationResult> =>
    ipcRenderer.invoke(Channels.ACTIVATION_ACTIVATE, email) as Promise<ActivationResult>,
  getActivationState: (): Promise<ActivationState | null> =>
    ipcRenderer.invoke(Channels.ACTIVATION_CHECK) as Promise<ActivationState | null>,
  checkPermissions: (): Promise<PermissionStatus> =>
    ipcRenderer.invoke(Channels.ONBOARDING_CHECK_PERMISSIONS) as Promise<PermissionStatus>,
  requestPermission: (
    type: 'camera' | 'microphone' | 'screenRecording' | 'accessibility',
  ): Promise<boolean> =>
    ipcRenderer.invoke(Channels.ONBOARDING_REQUEST_PERMISSION, type) as Promise<boolean>,
  checkDependencies: (): Promise<DependencyStatus> =>
    ipcRenderer.invoke(Channels.ONBOARDING_CHECK_DEPENDENCIES) as Promise<DependencyStatus>,
  installDependency: (name: 'ffmpeg'): Promise<void> =>
    ipcRenderer.invoke(Channels.ONBOARDING_INSTALL_DEPENDENCY, name) as Promise<void>,
  onInstallProgress: (callback: (progress: InstallProgress) => void): void => {
    ipcRenderer.on(Channels.ONBOARDING_INSTALL_PROGRESS, (_event, progress: InstallProgress) =>
      callback(progress),
    );
  },
  completeOnboarding: (): void => ipcRenderer.send(Channels.ONBOARDING_COMPLETE),
  quit: (): void => ipcRenderer.send(Channels.APP_QUIT),
  openExternal: (url: string): Promise<void> =>
    ipcRenderer.invoke(Channels.APP_OPEN_EXTERNAL, url) as Promise<void>,
};

contextBridge.exposeInMainWorld('onboardingAPI', onboardingAPI);
